using Avalonia;
using Avalonia.Controls;
using Avalonia.Controls.Presenters;
using Avalonia.Threading;
using Avalonia.VisualTree;
using VisualRelay.App.ViewModels;
using VisualRelay.App.Views;
using VisualRelay.App.Views.Controls;

namespace VisualRelay.Tests;

/// <summary>
/// Regression anchor for the markdown / attachments scroll-bottom clipping
/// defect in <see cref="TaskDetailPanel"/>.
///
/// Root cause: the three scrollable tabs (Markdown read-only, Context,
/// Attachments) use <see cref="ScrollViewer.Padding"/> for content inset
/// with only 8 px on the bottom — too little to clear the 21 px
/// <see cref="TextBlock.LineHeight"/> or attachment row height.  In
/// Avalonia, <c>Padding</c> on a <see cref="ScrollViewer"/> is added
/// <em>outside</em> the content's measured extent, so the scroll thumb
/// cannot reveal the padded region, clipping the last line/item.
///
/// Fix: move the bottom inset off <see cref="ScrollViewer.Padding"/> and
/// onto the inner content element as <see cref="Border.Margin"/>, so the
/// bottom gap is part of the measured extent and the last item stays
/// reachable.  This is the same pattern already established in
/// <see cref="StageInputView"/> (line 104-105) and
/// <see cref="StageOutputView"/> (line 116-117).
/// </summary>
[Collection("Headless")]
public sealed class TaskDetailScrollBottomReachabilityTests
{
    // Enough markdown lines to overflow the Markdown tab viewport at
    // window height 600 so the extent-vs-bottom assertions are meaningful.
    private static readonly string OverflowingMarkdown =
        "# Scroll Reach Test\n\n" +
        string.Join("\n", Enumerable.Range(1, 40).Select(i =>
            $"Line {i:D2}: The quick brown fox jumps over the lazy dog repeatedly."));

    // ── Structural: Markdown read-only ──────────────────────────────────

    /// <summary>
    /// The <see cref="TextBlock"/> inside the Markdown read-only
    /// <see cref="ScrollViewer"/> must carry a bottom
    /// <see cref="Border.Margin"/> ≥ 16 px so the last line of text
    /// clears the viewport bottom edge when scrolled fully down.
    /// Before the fix the bottom inset lived on
    /// <see cref="ScrollViewer.Padding"/> (only 8 px); the inner
    /// <see cref="TextBlock"/> had zero margin.
    /// </summary>
    [AvaloniaFact]
    public async Task MarkdownReadOnly_TextBlock_MarginBottom_IsSixteenOrMore()
    {
        // ── Arrange ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("scroll-markdown", OverflowingMarkdown);

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks[0];
        await viewModel.LastSelectionLoad!;
        Dispatcher.UIThread.RunJobs();

        viewModel.SelectedTabIndex = 0; // Markdown tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 600
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act: find the read-only Markdown ScrollViewer → TextBlock ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        // The read-only markdown ScrollViewer wraps a plain TextBlock
        // (the error-area ScrollViewer wraps a SelectableTextBlock).
        var markdownScrollViewer = taskDetailPanel.GetVisualDescendants()
            .OfType<ScrollViewer>()
            .FirstOrDefault(sv => sv.IsVisible &&
                sv.GetVisualChildren().OfType<TextBlock>().Any());

        Assert.NotNull(markdownScrollViewer);

        var textBlock = markdownScrollViewer!.GetVisualChildren()
            .OfType<TextBlock>()
            .First();

        // ── Assert: TextBlock.Margin.Bottom ≥ 16 ──
        Assert.True(
            textBlock.Margin.Bottom >= 16,
            $"Markdown read-only TextBlock Margin.Bottom is {textBlock.Margin.Bottom}, " +
            "must be ≥ 16.  Before the fix ScrollViewer.Padding carried only 8 px " +
            "bottom, which is outside the measured extent and clips the last line.");
    }

    // ── Structural: Context ─────────────────────────────────────────────

    /// <summary>
    /// The <see cref="TextBlock"/> inside the Context tab
    /// <see cref="ScrollViewer"/> must carry a bottom
    /// <see cref="Border.Margin"/> ≥ 16 px — same class of defect as the
    /// Markdown tab.
    /// </summary>
    [AvaloniaFact]
    public async Task ContextTab_TextBlock_MarginBottom_IsSixteenOrMore()
    {
        // ── Arrange ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("scroll-context", "# Context Scroll Test\n\n" +
            string.Join("\n", Enumerable.Range(1, 30).Select(i =>
                $"Context line {i:D2}: some context information here.")));

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks[0];
        await viewModel.LastSelectionLoad!;
        Dispatcher.UIThread.RunJobs();

        viewModel.SelectedTabIndex = 1; // Context tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 600
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act: find the Context ScrollViewer → TextBlock ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        // The Context tab ScrollViewer wraps a plain TextBlock.
        var contextScrollViewer = taskDetailPanel.GetVisualDescendants()
            .OfType<ScrollViewer>()
            .FirstOrDefault(sv => sv.IsVisible &&
                sv.GetVisualChildren().OfType<TextBlock>().Any());

        Assert.NotNull(contextScrollViewer);

        var textBlock = contextScrollViewer!.GetVisualChildren()
            .OfType<TextBlock>()
            .First();

        // ── Assert: TextBlock.Margin.Bottom ≥ 16 ──
        Assert.True(
            textBlock.Margin.Bottom >= 16,
            $"Context tab TextBlock Margin.Bottom is {textBlock.Margin.Bottom}, " +
            "must be ≥ 16.  Before the fix ScrollViewer.Padding carried only 8 px " +
            "bottom, clipped outside the measured extent.");
    }

    // ── Structural: Attachments ─────────────────────────────────────────

    /// <summary>
    /// The <see cref="ItemsControl"/> inside the Attachments tab
    /// <see cref="ScrollViewer"/> must carry a bottom
    /// <see cref="Border.Margin"/> ≥ 16 px so the last attachment row is
    /// fully visible when scrolled to the bottom.
    /// </summary>
    [AvaloniaFact]
    public async Task AttachmentsTab_ItemsControl_MarginBottom_IsSixteenOrMore()
    {
        // ── Arrange: task with many attachments to force overflow ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        var siblings = Enumerable.Range(1, 20)
            .Select(i => ($"attachment-file-{i:D2}.txt", $"content {i}"))
            .ToArray();
        repo.WriteNestedTask("scroll-attachments", "# Attachments Scroll Test\n", siblings);

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "scroll-attachments");
        viewModel.SelectedTabIndex = 2; // Attachments tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 600
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act: find the Attachments ScrollViewer → ItemsControl ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        var attachmentsScrollViewer = taskDetailPanel.GetVisualDescendants()
            .OfType<ScrollViewer>()
            .FirstOrDefault(sv => sv.IsVisible &&
                sv.GetVisualChildren().OfType<ItemsControl>().Any());

        Assert.NotNull(attachmentsScrollViewer);

        var itemsControl = attachmentsScrollViewer!.GetVisualChildren()
            .OfType<ItemsControl>()
            .First();

        // ── Assert: ItemsControl.Margin.Bottom ≥ 16 ──
        Assert.True(
            itemsControl.Margin.Bottom >= 16,
            $"Attachments ItemsControl Margin.Bottom is {itemsControl.Margin.Bottom}, " +
            "must be ≥ 16.  Before the fix ScrollViewer.Padding carried only 8 px " +
            "bottom, outside the measured extent — last attachment row clips.");
    }

    // ── Behavioural: Markdown extent reaches last line ──────────────────

    /// <summary>
    /// The Markdown read-only <see cref="ScrollViewer"/>'s vertical extent
    /// must contain the bottom edge of the <see cref="TextBlock"/> with
    /// at least a 2 px gap, proving the last line is reachable.
    /// </summary>
    [AvaloniaFact]
    public async Task MarkdownReadOnly_Extent_ReachesTextBlockBottom_WithGap()
    {
        // ── Arrange ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);
        repo.WriteTask("scroll-md-extent", OverflowingMarkdown);

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks[0];
        await viewModel.LastSelectionLoad!;
        Dispatcher.UIThread.RunJobs();

        viewModel.SelectedTabIndex = 0; // Markdown tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 600
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        var scrollViewer = taskDetailPanel.GetVisualDescendants()
            .OfType<ScrollViewer>()
            .FirstOrDefault(sv => sv.IsVisible &&
                sv.GetVisualChildren().OfType<TextBlock>().Any());

        Assert.NotNull(scrollViewer);

        var textBlock = scrollViewer!.GetVisualChildren()
            .OfType<TextBlock>()
            .First();

        // Content must overflow the viewport for the assertion to be meaningful.
        Assert.True(
            textBlock.Bounds.Height > scrollViewer.Viewport.Height,
            $"TextBlock height ({textBlock.Bounds.Height:0.##}) does not overflow " +
            $"viewport ({scrollViewer.Viewport.Height:0.##})");

        var textBlockBottom = ContentBottom(textBlock, scrollViewer);

        // ── Assert: extent reaches the TextBlock bottom with a gap ──
        Assert.True(
            scrollViewer.Extent.Height >= textBlockBottom,
            $"Extent {scrollViewer.Extent.Height:0.##} does not reach " +
            $"TextBlock bottom {textBlockBottom:0.##}");

        Assert.True(
            scrollViewer.Extent.Height - textBlockBottom >= 2.0,
            $"No bottom gap: extent {scrollViewer.Extent.Height:0.##} vs " +
            $"TextBlock bottom {textBlockBottom:0.##}.  The 16 px bottom margin " +
            "must be part of the measured extent.");
    }

    // ── Behavioural: Attachments extent reaches last item ───────────────

    /// <summary>
    /// The Attachments <see cref="ScrollViewer"/>'s vertical extent must
    /// contain the bottom edge of the last attachment row with at least a
    /// 2 px gap.
    /// </summary>
    [AvaloniaFact]
    public async Task AttachmentsTab_Extent_ReachesLastItemBottom_WithGap()
    {
        // ── Arrange ──
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", []);

        var siblings = Enumerable.Range(1, 20)
            .Select(i => ($"attachment-file-{i:D2}.txt", $"content {i}"))
            .ToArray();
        repo.WriteNestedTask("scroll-att-extent", "# Attachments Extent Test\n", siblings);

        var viewModel = new MainWindowViewModel { RootPath = repo.Root };
        await viewModel.LoadInitialAsync();

        viewModel.SelectedTask = viewModel.Tasks.Single(t => t.Id == "scroll-att-extent");
        viewModel.SelectedTabIndex = 2; // Attachments tab
        Dispatcher.UIThread.RunJobs();

        var window = new MainWindow
        {
            DataContext = viewModel,
            Width = 900,
            Height = 600
        };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        // ── Act ──
        var taskDetailPanel = window.GetVisualDescendants()
            .OfType<TaskDetailPanel>()
            .Single();

        var scrollViewer = taskDetailPanel.GetVisualDescendants()
            .OfType<ScrollViewer>()
            .FirstOrDefault(sv => sv.IsVisible &&
                sv.GetVisualChildren().OfType<ItemsControl>().Any());

        Assert.NotNull(scrollViewer);

        var itemsControl = scrollViewer!.GetVisualChildren()
            .OfType<ItemsControl>()
            .First();

        // Content must overflow.
        Assert.True(
            itemsControl.Bounds.Height > scrollViewer.Viewport.Height,
            $"ItemsControl height ({itemsControl.Bounds.Height:0.##}) does not overflow " +
            $"viewport ({scrollViewer.Viewport.Height:0.##})");

        var lastBorder = LastItemBorder(itemsControl);
        var lastBottom = ContentBottom(lastBorder, scrollViewer);

        // ── Assert ──
        Assert.True(
            scrollViewer.Extent.Height >= lastBottom,
            $"Extent {scrollViewer.Extent.Height:0.##} does not reach " +
            $"last item bottom {lastBottom:0.##}");

        Assert.True(
            scrollViewer.Extent.Height - lastBottom >= 2.0,
            $"No bottom gap: extent {scrollViewer.Extent.Height:0.##} vs " +
            $"last item bottom {lastBottom:0.##}.  The 16 px bottom margin " +
            "on the ItemsControl must be part of the measured extent.");
    }

    // ── Helpers ────────────────────────────────────────────────────────

    /// <summary>
    /// Bottom edge of <paramref name="control"/> in the
    /// <see cref="ScrollViewer"/>'s content coordinate space.
    /// </summary>
    private static double ContentBottom(Visual control, ScrollViewer scrollViewer)
    {
        var presenter = scrollViewer.GetVisualDescendants()
            .OfType<ScrollContentPresenter>()
            .First();
        var topLeft = control.TranslatePoint(new Point(0, 0), presenter)
            ?? new Point(0, 0);
        return topLeft.Y + scrollViewer.Offset.Y + control.Bounds.Height;
    }

    /// <summary>
    /// The last item container <see cref="Border"/> produced by the
    /// <paramref name="itemsControl"/>.
    /// </summary>
    private static Border LastItemBorder(ItemsControl itemsControl)
    {
        var borders = new List<Border>();
        foreach (var presenter in itemsControl.GetVisualDescendants()
                     .OfType<ContentPresenter>())
        {
            var border = presenter.GetVisualChildren()
                .OfType<Border>()
                .FirstOrDefault();
            if (border is not null)
                borders.Add(border);
        }

        Assert.NotEmpty(borders);
        return borders[^1];
    }
}

